def test_read_git_short_hash_from_files_reads_branch_ref(tmp_path):
    git_dir = tmp_path / ".git"
    refs_dir = git_dir / "refs" / "heads"
    refs_dir.mkdir(parents=True)
    (git_dir / "HEAD").write_text("ref: refs/heads/main\n", encoding="utf-8")
    (refs_dir / "main").write_text(
        "0123456789abcdef0123456789abcdef01234567\n",
        encoding="utf-8",
    )

    assert commands._read_git_short_hash_from_files(tmp_path) == "0123456"


def test_get_solver_version_does_not_spawn_git(monkeypatch):
    def fail_git(*_args, **_kwargs):
        raise AssertionError("solver version lookup must not spawn git")

    monkeypatch.setattr(commands.subprocess, "run", fail_git)
    monkeypatch.setattr(
        commands,
        "_read_git_short_hash_from_files",
        lambda _repo: "abcdef0",
    )

    version = commands._get_solver_version()

    assert version.startswith("rust-")
    assert version.endswith("-abcdef0")


def test_lightning_ocr_texts_from_image_keeps_top_nonempty_candidate(
    monkeypatch,
    tmp_path,
):
    screenshot = tmp_path / "screen.png"
    screenshot.write_text("placeholder")

    class FakeCandidate:
        def __init__(self, text):
            self.text = text

        def string(self):
            return self.text

    class FakeObservation:
        def __init__(self, candidates):
            self.candidates = candidates

        def topCandidates_(self, count):
            return [FakeCandidate(text) for text in self.candidates[:count]]

    class FakeRequest:
        @classmethod
        def alloc(cls):
            return cls()

        def init(self):
            return self

        def setRecognitionLevel_(self, _level):
            pass

        def setUsesLanguageCorrection_(self, _enabled):
            pass

        def results(self):
            return [
                FakeObservation(["Best text", "Worse text"]),
                FakeObservation(["", "Fallback text"]),
            ]

    class FakeHandler:
        @classmethod
        def alloc(cls):
            return cls()

        def initWithURL_options_(self, _url, _options):
            return self

        def performRequests_error_(self, _requests, _error):
            return True

    def fake_load_bundle(_name, namespace, *, bundle_path):
        namespace["VNRecognizeTextRequest"] = FakeRequest
        namespace["VNImageRequestHandler"] = FakeHandler

    monkeypatch.setitem(
        sys.modules,
        "objc",
        SimpleNamespace(loadBundle=fake_load_bundle),
    )
    monkeypatch.setitem(
        sys.modules,
        "Foundation",
        SimpleNamespace(
            NSURL=SimpleNamespace(
                fileURLWithPath_=lambda path: f"file://{path}",
            )
        ),
    )

    result = commands._lightning_ocr_texts_from_image(screenshot)

    assert result == {"status": "OK", "texts": ["Best text", "Fallback text"]}


def test_abandon_pilot_slot_targets_first_carry_forward_portrait():
    from src.control.mac_click import list_known_window_controls

    controls = list_known_window_controls()
    available = controls["abandon_pilot_available"]
    confirm = controls["abandon_confirm_yes"]
    control = controls["abandon_pilot_slot"]
    two_left = controls["abandon_pilot_slot_two_left"]
    two_right = controls["abandon_pilot_slot_two_right"]
    wide = controls["abandon_pilot_slot_wide"]
    right = controls["abandon_pilot_slot_right"]

    assert available["window_x"] == 95
    assert available["window_y"] == 254
    if os.name == "nt":
        assert confirm["window_x"] == 1208
        assert confirm["window_y"] == 795
        assert control["window_x"] == 1205
        assert control["window_y"] == 660
        assert two_left["window_x"] == 1205
        assert two_left["window_y"] == 660
        assert two_right["window_x"] == 1385
        assert two_right["window_y"] == 660
        assert wide["window_x"] == 1295
        assert wide["window_y"] == 660
        assert right["window_x"] == 1385
        assert right["window_y"] == 660
    else:
        assert confirm["window_x"] == 496
        assert confirm["window_y"] == 445
        assert control["window_x"] == 491
        assert control["window_y"] == 329
        assert two_left["window_x"] == 562
        assert two_left["window_y"] == 329
        assert two_right["window_x"] == 704
        assert two_right["window_y"] == 329
        assert wide["window_x"] == 632
        assert wide["window_y"] == 329
        assert right["window_x"] == 773
        assert right["window_y"] == 329


