def test_lightning_terminal_evidence_handles_structured_and_split_objectives():
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "objectives": [
                {"text": "Protect the Train", "status": "failed"},
            ],
        }
    ) == {
        "kind": "objective_failure_field",
        "path": "objectives.0.status",
        "field": "status",
        "value": "failed",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "bonus_objectives": [
                {"text": "Block Vek Spawning", "failed": True},
            ],
        }
    ) == {
        "kind": "objective_failure_field",
        "path": "bonus_objectives.0.failed",
        "field": "failed",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "ocr_texts": [
                "Region Secured",
                "Protect the Train",
                "FAILED",
            ],
        }
    ) == {
        "kind": "split_objective_failure_text",
        "path": "ocr_texts.2",
        "phrase": "failed",
        "context": "split_objective_text",
        "context_path": "ocr_texts.1",
        "context_text": "Protect the Train",
        "text": "FAILED",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "ocr": {
                "status": "OK",
                "texts": ["Region Secured", "Killed in Action"],
            },
        }
    ) == {
        "kind": "terminal_text",
        "path": "ocr.texts.1",
        "phrase": "killed in action",
        "text": "Killed in Action",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "ocr": {
                "status": "OK",
                "texts": ["Region Secured", "Protect the Train", "FAILED"],
            },
        }
    ) == {
        "kind": "split_objective_failure_text",
        "path": "ocr.texts.2",
        "phrase": "failed",
        "context": "split_objective_text",
        "context_path": "ocr.texts.1",
        "context_text": "Protect the Train",
        "text": "FAILED",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "ocr": {"status": "OK", "lines": ["K.I.A."]},
        }
    ) == {
        "kind": "terminal_text",
        "path": "ocr.lines.0",
        "phrase": "kia",
        "text": "K.I.A.",
    }
    assert (
        commands._lightning_terminal_outcome_evidence(
            {"status": "OK", "texts": ["Protect the Train", "FAILED"]}
        )
        is None
    )


def test_lightning_speed_policy_allows_time_pod_failure_only():
    time_pod_panel = {
        "status": "OK",
        "visible_ui": "reward_panel",
        "recommended_control": "reward_continue",
        "visible_text": "Region Secured\nProtect the Time Pod (Failed)",
    }

    assert commands._lightning_terminal_outcome_evidence(time_pod_panel) == {
        "kind": "terminal_text",
        "path": "visible_text",
        "phrase": "(failed)",
        "text": "Region Secured\nProtect the Time Pod (Failed)",
    }
    assert (
        commands._lightning_terminal_outcome_evidence(
            time_pod_panel,
            lightning_speed_loss_policy=True,
        )
        is None
    )
    assert (
        commands._lightning_terminal_outcome_evidence(
            {
                "status": "OK",
                "visible_ui": "reward_panel",
                "objectives": [
                    {"text": "Protect the Time Pod", "status": "failed"},
                ],
            },
            lightning_speed_loss_policy=True,
        )
        is None
    )
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "visible_text": (
                "Region Secured\nProtect the Time Pod (Failed)\nTimeline Lost"
            ),
        },
        lightning_speed_loss_policy=True,
    ) == {
        "kind": "terminal_text",
        "path": "visible_text",
        "phrase": "timeline lost",
        "text": "Region Secured\nProtect the Time Pod (Failed)\nTimeline Lost",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "objectives": [
                {"text": "Protect the Train", "status": "failed"},
            ],
        },
        lightning_speed_loss_policy=True,
    ) == {
        "kind": "objective_failure_field",
        "path": "objectives.0.status",
        "field": "status",
        "value": "failed",
    }
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "visible_text": (
                "Region Secured\n"
                "Protect the Time Pod (Failed)\n"
                "Defend the Train (Failed)"
            ),
        },
        lightning_speed_loss_policy=True,
    ) is not None
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "ocr_texts": [
                "Region Secured",
                "Protect the Time Pod",
                "(Failed)",
                "Defend the Train",
                "(Failed)",
            ],
        },
        lightning_speed_loss_policy=True,
    ) is not None
    assert commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "reward_panel",
            "objectives": [
                {"text": "Protect the Time Pod", "status": "failed"},
                {"text": "Defend the Train", "status": "failed"},
            ],
        },
        lightning_speed_loss_policy=True,
    ) is not None


def test_lightning_terminal_outcome_detects_visual_kia_without_ocr(tmp_path):
    from PIL import Image, ImageDraw

    image = Image.new("RGB", (1280, 748), (8, 10, 14))
    draw = ImageDraw.Draw(image)
    draw.rectangle([660, 470, 725, 510], fill=(170, 40, 45))
    path = tmp_path / "visual_kia.png"
    image.save(path)

    result = commands._lightning_terminal_outcome_evidence(
        {
            "status": "OK",
            "visible_ui": "perfect_reward_choice",
            "recommended_control": "perfect_reward_grid",
            "screenshot_path": str(path),
        }
    )

    assert result["kind"] == "terminal_visual_kia"
    assert result["phrase"] == "kia"
    assert result["red_pixels"] >= 180


