def test_lightning_route_start_recovers_vetoed_active_mission_before_probe_click(
    monkeypatch,
):
    session = RunSession(
        run_id="lw",
        squad="Blitzkrieg",
        difficulty=0,
        achievement_targets=["Lightning War"],
    )
    calls = []
    blocks = []
